#!/usr/bin/env python3
from pathlib import Path
from datetime import datetime
import base64, subprocess, sys
APP = Path("apps/pfotentechnik")
DOMAIN = APP / "src/domain/recommendationLinks.ts"
COMPONENT = APP / "src/components/DecisionNextSteps.astro"
COMPONENT_CONTENT = base64.b64decode("").decode("utf-8")
def stop(message):
    print(f"FEHLER: {message}", file=sys.stderr)
    raise SystemExit(1)
def find_root(start):
    for candidate in (start, *start.parents):
        if (candidate / APP / "package.json").is_file(): return candidate
    stop("Repository-Root nicht gefunden.")
def replace_once(text, old, new, label):
    count = text.count(old)
    if count != 1: stop(f"{label}: genau 1 Fundstelle erwartet, gefunden: {count}")
    return text.replace(old, new, 1)
def run(command, cwd):
    print("$", " ".join(command))
    if subprocess.run(command, cwd=cwd).returncode != 0:
        raise RuntimeError("Befehl fehlgeschlagen: " + " ".join(command))
root = find_root(Path.cwd().resolve())
for relative in [DOMAIN, COMPONENT]:
    if not (root / relative).is_file(): stop(f"Datei fehlt: {relative}")
domain_original = (root / DOMAIN).read_text(encoding="utf-8")
component_original = (root / COMPONENT).read_text(encoding="utf-8")
if "recommendation-cards-2.0" in component_original: stop("Recommendation Cards 2.0 scheint bereits installiert zu sein.")
domain = replace_once(domain_original, "export type RecommendationLink = { eyebrow: string; title: string; text: string; href: string; label: string };", "export type RecommendationLink = {\n  kind?: \"product\" | \"comparison\" | \"guide\" | \"manufacturer\";\n  eyebrow: string;\n  title: string;\n  text?: string;\n  href: string;\n  label: string;\n  image?: { src: any; alt?: string };\n  score?: number;\n  stat?: { value: string; label: string };\n  highlights?: string[];\n};", "RecommendationLink erweitern")
domain = replace_once(domain, "const productLink = (entry: RecommendationEntry): RecommendationLink => ({\n  eyebrow: \"Top-Empfehlung\", title: entry.data.title,\n  text: entry.data.recommendation ?? \"Öffne die vollständige redaktionelle Einordnung dieses Modells.\",\n  href: `/produkt/${entry.data.slug}/`, label: \"Produkt ansehen\"\n});\nconst comparisonLink = (entry: RecommendationEntry): RecommendationLink => ({\n  eyebrow: \"Vergleich\", title: entry.data.title,\n  text: entry.data.description ?? \"Vergleiche passende Modelle direkt miteinander.\",\n  href: `/vergleiche/${entry.data.slug}/`, label: \"Zum Vergleich\"\n});", "const productLink = (entry: RecommendationEntry): RecommendationLink => ({\n  kind: \"product\",\n  eyebrow: \"Top-Empfehlung\",\n  title: entry.data.title,\n  text: entry.data.recommendation ?? \"Öffne die vollständige redaktionelle Einordnung dieses Modells.\",\n  href: `/produkt/${entry.data.slug}/`,\n  label: \"Produkt ansehen\",\n  image: entry.data.images\n    ? {\n        src:\n          entry.data.images.comparison?.src ??\n          entry.data.images.thumbnail?.src ??\n          entry.data.images.hero?.src ??\n          entry.data.images.comparison ??\n          entry.data.images.thumbnail ??\n          entry.data.images.hero,\n        alt:\n          entry.data.images.comparison?.alt ??\n          entry.data.images.thumbnail?.alt ??\n          entry.data.images.hero?.alt ??\n          entry.data.title\n      }\n    : undefined,\n  score:\n    typeof entry.data.score === \"number\"\n      ? entry.data.score\n      : typeof entry.data.rating === \"number\"\n        ? Math.round(entry.data.rating * 20)\n        : undefined,\n  highlights: [\n    ...asArray(entry.data.strengths),\n    ...asArray(entry.data.features)\n  ].map((value) => String(value)).filter(Boolean).slice(0, 3)\n});\nconst comparisonLink = (entry: RecommendationEntry): RecommendationLink => ({\n  kind: \"comparison\",\n  eyebrow: \"Vergleich\",\n  title: entry.data.title,\n  text: entry.data.description ?? \"Vergleiche passende Modelle direkt miteinander.\",\n  href: `/vergleiche/${entry.data.slug}/`,\n  label: \"Zum Vergleich\",\n  stat: {\n    value: String(asArray(entry.data.items).length || \"Alle\"),\n    label: asArray(entry.data.items).length === 1 ? \"Modell\" : \"Modelle\"\n  },\n  highlights: [\n    \"Pfotentechnik-Score\",\n    \"Modelle direkt filtern\",\n    \"Stärken und Grenzen vergleichen\"\n  ]\n});", "Produkt- und Vergleichskarten anreichern")
stamp = datetime.now().strftime("%Y-%m-%dT%H-%M-%S")
backup = root / f".recommendation-cards-2.0-backup-{stamp}"
backup.mkdir(parents=True, exist_ok=False)
for relative, content in [(DOMAIN, domain_original), (COMPONENT, component_original)]:
    dest = backup / relative
    dest.parent.mkdir(parents=True, exist_ok=True)
    dest.write_text(content, encoding="utf-8")
try:
    (root / DOMAIN).write_text(domain, encoding="utf-8")
    (root / COMPONENT).write_text(COMPONENT_CONTENT, encoding="utf-8")
    run(["npm", "run", "build:pfotentechnik"], root)
    package = (root / APP / "package.json").read_text(encoding="utf-8")
    if "\"audit:recommendations\"" in package:
        run(["npm", "--workspace", "apps/pfotentechnik", "run", "audit:recommendations"], root)
except Exception as exc:
    print(f"Validierung fehlgeschlagen: {exc}", file=sys.stderr)
    print("Automatischer Rollback wird ausgeführt.", file=sys.stderr)
    (root / DOMAIN).write_text(domain_original, encoding="utf-8")
    (root / COMPONENT).write_text(component_original, encoding="utf-8")
    raise SystemExit(1)
print("Recommendation Cards 2.0 erfolgreich installiert.")
print(f"Backup: {backup}")
